    ('ab5c1f22-eb41-5887-9322-ad84ece296d3'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Иволга', 'ivolga', 'Паспорт ВНИИк. Здоровая, без травм и дурных привычек, работает ежедневно в клубной смене, выезжает на конные прогулки в поля, прыгает под всадником до 80 см., спокойная.', 'c9177f30-c03c-5572-9a8d-030b6cfc6a75'::uuid, '0d73525f-ef44-5918-84bb-5b8729fc22bb'::uuid, 162, 'female', '2009-05-25'::date, NULL, 'ymd', 'hide', NULL, true),
