    ('df182216-4e9a-5655-9188-8865b7cf0968'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Играйка', 'igrayka', '157 см в холке. Напрыгана в шпринте до 130 см, маршруты до 100 см. Специализация - конкур, имеет опыт участия в соревнованиях. Честная, маневренная и очень энергичная. Здорова, документы ВНИИк. Спокойная, ничего не боится, выезжает в поля.', 'd2608fb6-fa1c-59e7-9071-1358fc59da52'::uuid, '6290fc60-7d96-5a9d-a37f-a9c33ab8cddf'::uuid, 157, 'female', '2012-04-17'::date, NULL, 'ymd', 'hide', NULL, true),
