    ('85d59f28-c498-5928-b964-332aa6a6fdd1'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Леди линн', 'ledi-linn', 'Была маткой в одном из самых крупных племенных хозяйств Голландии, так же является маткой пони-фермы ЦКСК "Александрова Дача", дала немало потомства высокого качества. Кобыла с очень спокойным характером, общительная, на шикарных высоких движениях, широкая и глубокая по экстерьеру, может работать под верхом, но имеет проблемы по здоровью (ламинит) - легкие нагрузки.', 'c7190645-0c63-5377-b38f-4fce2670ebae'::uuid, '0d73525f-ef44-5918-84bb-5b8729fc22bb'::uuid, NULL, 'female', '2000-05-12'::date, NULL, 'ymd', 'hide', NULL, true),
