    ('67a43c1c-6854-5e28-889a-df3283703d28'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Осси', 'ossi', 'Племенная Шетлендская пони яркой рыже-пегой масти, рост в перспективе до 105 см. Яркая малышка с голубыми глазами. копия своей мамы! От такой красотки глаз не отвести!', '076496bf-bb2d-5450-8618-8f06121a8b99'::uuid, '7b5123d7-d87e-53c1-ad5c-0bbd2b6d9dc1'::uuid, 105, 'female', '2023-05-15'::date, NULL, 'ymd', 'hide', NULL, true),
    ('ba9edea9-c19e-5907-8888-13be37cac688'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Отважный', 'otvazhnyy', 'Легкий, на шикарных высоких движениях. Жеребчик перспективен в серьезный спорт (выездка, конкур). Так же пойдет под разведение. Продается только в опытные, знающие дело руки. Жеребчик заезжен, под седлом не работает, только корда и ежедневный выгул. Здоровый, без пороков и травм. С рождения получает все необходимые добавки. Документы ВНИИК - племенные.', '70d58bad-7033-5db3-84ef-98945cd5af7b'::uuid, '69b17ced-9297-5b53-a461-668457b527fd'::uuid, NULL, 'male', '2015-02-27'::date, NULL, 'ymd', 'hide', NULL, true),
