    ('06675ddd-4d9f-59ec-a9e1-9e4d2c535a2c'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Реприза', 'repriza', 'Заезженная под седло - спокойная, работает в смене под детьми, иногда прыгает барьерчики до 70 см, сильно не форсируется, техничный прыжок. Её отец один из лучших представителей породы, а отец Рэзака - Рэтив скакавший 20 раз и 16 раз из них был первым! Это лучший жеребец в породе. Его дети отличаются прекрасным экстерьером и высокой работоспособностью и в скаковых испытаниях и в конном спорте. Отец по маме будённовский жеребец Землемер. Он чуть было не стал трижды венчанным. Он провел всего 12 скачек в 2 и', 'b2d3ccba-d97b-59eb-9fc8-399f3a3a22c3'::uuid, '6290fc60-7d96-5a9d-a37f-a9c33ab8cddf'::uuid, 160, 'female', '2014-01-14'::date, NULL, 'ymd', 'hide', NULL, true),
