    ('e8792c8c-be25-5f69-b160-a5cbcde6dee1'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Феерия витта', 'feeriya-vitta', 'Чистопородная кобыла, документы ВНИИк, рост в перспективе до 165 см. Получает подкормки, выгул - весь световой день, здоровая, без пороков, шикарная родословная.', '70d58bad-7033-5db3-84ef-98945cd5af7b'::uuid, 'a0524f66-3980-507d-b06d-6d9b5c465c2f'::uuid, NULL, 'female', '2016-02-19'::date, NULL, 'ymd', 'hide', NULL, true),
