    ('6c0efa5d-1303-50f1-803a-dfef45a89642'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Чаинка', 'chainka', NULL, NULL, NULL, NULL, 'female', '1982-01-01'::date, NULL, 'y', 'hide', NULL, false),
    ('ae5315d3-e849-5e86-80c3-c65c8bbf2663'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Чайка iв', 'chayka-iv', NULL, NULL, NULL, NULL, 'female', NULL, NULL, 'hide', 'hide', NULL, false),
    ('fdfcb695-0536-589c-907d-9346e518dd41'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Чародей', 'charodey', 'Честный спортивный конь, ходил маршруты до 100 см, хорошо выезжен, подойдет под любой уровень всадника. Отличный хобби-вариант. Есть особенности по здоровью. Сейчас в тренинге. Все документы в наличии.', 'b2d3ccba-d97b-59eb-9fc8-399f3a3a22c3'::uuid, '6290fc60-7d96-5a9d-a37f-a9c33ab8cddf'::uuid, 165, 'male', '2008-01-01'::date, NULL, 'y', 'hide', NULL, true),
    ('2910731b-9245-58dc-a688-70ab50cb89a2'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Челентано', 'chelentano', 'Гнедо-чалая масть зимой становится с розовым оттенком. Шикарный конь с огромным потенциалом в спорт, талантлив в дрессуре, здоров, колется, бреется, расчищается, моется без проблем. Умения Челентано - заворожить своей красотой, длинной гривой, грациозными движениями, но кроме этого он выполняет многие элементы выездки: все переходы, все боковые элементы, пассаж, пиаффе, менки ног в воздухе, трюковые элементы - лежать, сидеть, испанский шаг, пенек. Мерин очень умный - "ловит все на лету", а так же отличный', '92e16c1e-bbd4-537b-87e6-edb9495f0107'::uuid, '4812920e-a92a-5c4f-9c97-5d0f2ea4313c'::uuid, 140, 'male', '2007-05-23'::date, NULL, 'ymd', 'hide', NULL, true),
    ('0b30c899-a324-53d4-9c99-2d33abb3b19b'::uuid, '5f6496aa-4fe9-42da-a763-29f9bab22d73'::uuid, 'Челита', 'chelita', NULL, NULL, NULL, NULL, 'female', '1992-01-01'::date, NULL, 'y', 'hide', NULL, false),
